import CheckoutSteps from '../components/CheckoutSteps';
import FormContainer from '../components/FormContainer';

const ShippingScreen = ({ onSubmit }) => {
  return (
    <FormContainer>
      <CheckoutSteps active={1} />
      <h1>Podaci o razmeni</h1>
      <form
        onSubmit={(event) => {
          event.preventDefault();
          onSubmit();
        }}
      >
        <label>
          Adresa preuzimanja
          <input required placeholder="Unesite adresu" />
        </label>
        <label>
          Grad
          <input required placeholder="Unesite grad" />
        </label>
        <label>
          Period razmene
          <select defaultValue="21 dana">
            <option>14 dana</option>
            <option>21 dana</option>
            <option>30 dana</option>
          </select>
        </label>
        <button type="submit">Nastavi</button>
      </form>
    </FormContainer>
  );
};

export default ShippingScreen;
